<template><el-card><template #header>待我审核 / 审核任务池</template><DataTable :data="rows"><el-table-column prop="title" label="审核标题" min-width="260"/><el-table-column prop="objectType" label="审核对象"/><el-table-column prop="submitter" label="提交人"/><el-table-column prop="submittedAt" label="提交时间"/><el-table-column prop="score" label="质量评分"/><el-table-column label="风险"><template #default="s"><StatusTag :value="s.row.risk"/></template></el-table-column><el-table-column prop="status" label="状态"/><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="task=s.row">审核详情</el-button></template></el-table-column></DataTable><DetailDrawer v-model="open" title="审核详情"><el-card><template #header>待审核内容</template>{{task?.title}}</el-card><div class="two-col mt"><el-card>变更前：旧版本内容、规则、权限。</el-card><el-card>变更后：新增依据锚点、优化技能触发意图。</el-card></div><ReviewPanel class="mt" :score="task?.score||0" :risk="task?.risk||'low'" @approve="set('approved')" @reject="set('rejected')" @return="set('returned')"/></DetailDrawer></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { reviewTasks } from '@/mock/data'; import DataTable from '@/components/DataTable.vue'; import StatusTag from '@/components/StatusTag.vue'; import DetailDrawer from '@/components/DetailDrawer.vue'; import ReviewPanel from '@/components/ReviewPanel.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(reviewTasks))); const task=ref<any>(); const open=computed({get:()=>!!task.value,set:v=>{if(!v)task.value=null}}); function set(s:string){task.value.status=s; task.value=null}</script>
